const JSONBIN_KEY = '$2a$10$s6xjZMcPdNdcQCBdKuAWNeabgI7Q4/.KFvizSqu5xw3WQfL5hkXoC';
const JSONBIN_URL = 'https://api.jsonbin.io/v3/b/' + JSONBIN_BIN_ID;

// Cache local para no llamar JSONBin en cada request
let dbCache = null;
let dbDirty = false;
let saveTimer = null;

async function loadDB() {
  if (dbCache) return dbCache;
  try {
    const https = require('https');
    const data = await new Promise((resolve, reject) => {
      const req = https.get(JSONBIN_URL + '/latest', {
        headers: { 'X-Master-Key': JSONBIN_KEY }
      }, (res) => {
        let body = '';
        res.on('data', d => body += d);
        res.on('end', () => {
          try { resolve(JSON.parse(body)); } catch(e) { reject(e); }
        });
      });
      req.on('error', reject);
      req.setTimeout(8000, () => { req.destroy(); reject(new Error('timeout')); });
    });
    dbCache = data.record || { apps: [], ratings: [] };
    console.log('DB cargada desde JSONBin: ' + (dbCache.apps || []).length + ' apps');
    return dbCache;
  } catch(e) {
    console.error('Error cargando JSONBin:', e.message);
    if (!dbCache) dbCache = { apps: [], ratings: [] };
    return dbCache;
  }
}

function saveDB(db) {
  dbCache = db;
  // Debounce: espera 2s antes de guardar para agrupar cambios
  if (saveTimer) clearTimeout(saveTimer);
  saveTimer = setTimeout(() => flushDB(), 2000);
}

async function flushDB() {
  try {
    const https = require('https');
    const body = JSON.stringify(dbCache);
    await new Promise((resolve, reject) => {
      const url = new URL(JSONBIN_URL);
      const req = https.request({
        hostname: url.hostname,
        path: url.pathname,
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'X-Master-Key': JSONBIN_KEY,
          'Content-Length': Buffer.byteLength(body)
        }
      }, (res) => {
        res.resume();
        res.on('end', resolve);
      });
      req.on('error', reject);
      req.setTimeout(10000, () => { req.destroy(); reject(new Error('timeout')); });
      req.write(body);
      req.end();
    });
    console.log('DB guardada en JSONBin OK');
  } catch(e) {
    console.error('Error guardando JSONBin:', e.message);
  }
}

