function json(res, data, status) {
  status = status || 200;
  res.writeHead(status, { 'Content-Type':'application/json', 'Access-Control-Allow-Origin':'*' });
  res.end(JSON.stringify(data));
}
function fmtSize(b) { if(!b) return '--'; if(b<1048576) return (b/1024).toFixed(1)+' KB'; return (b/1048576).toFixed(1)+' MB'; }
function appView(a) {
  var r = a.rating_count > 0 ? (a.rating_sum/a.rating_count) : 0;
  return Object.assign({}, a, {rating: Math.round(r*10)/10, size: fmtSize(a.size_bytes)});
}
function readBody(req) {
  return new Promise(function(res,rej){
    var c=[]; req.on('data',function(d){c.push(d);}); req.on('end',function(){res(Buffer.concat(c));}); req.on('error',rej);
  });
}

